+
+            // return the combined result
+            vec3 C = reflection.mul(fresnel).add(scattering);
+            fragColor = vec4.vec4(clamp(aces_tonemap(C.mul(2.0f)), 0f, 1f), 1.0f);
+            return fragColor;
+        }
+    };
